from flask import Flask, request, jsonify

app = Flask(__name__)

# Load Ethereum private key (replace with your own)
private_key = "your_private_key_here"

def load_private_key(private_key):
    try:
        return serialization.load_pem_private_key(
            private_key.encode(),
            password=None,
            backend=default_backend()
        )
    except ValueError as e:
        print(f"Error loading private key: {e}")
        return None

def recover_address(message, signature):
    w3 = Web3()
    recovered_address = w3.eth.account.recover_message(message, signature=signature)
    return recovered_address.lower()

@app.route('/verify', methods=['POST'])
def verify_signature():
    data = request.json
    message = data.get('message')
    signature = data.get('signature')

    if not message or not signature:
        return jsonify({'error': 'Missing required fields'}), 400

    private_key_obj = load_private_key(private_key)
    if private_key_obj is None:
        return jsonify({'error': 'Failed to load private key'}), 500

    recovered_address = recover_address(message, signature)

    # Verify the message was signed by the expected address
    w3 = Web3()
    sender_address = w3.eth.account.recover_message(message, signature=signature)
    if sender_address.lower() != recovered_address:
        return jsonify({'error': 'Invalid signature'}), 401

    return jsonify({'success': True}), 200

